import { useState, useEffect } from 'react';
import axios from 'axios';
import Upload from '../components/Upload';
import Summary from '../components/Summary';
import Quiz from '../components/Quiz';
import Chat from '../components/Chat';

const Dashboard = () => {
  const [documents, setDocuments] = useState([]);
  const [selectedDoc, setSelectedDoc] = useState(null);

  useEffect(() => {
    const fetchDocuments = async () => {
      const token = localStorage.getItem('token');
      if (token) {
        try {
          const res = await axios.get('http://localhost:5000/api/documents', { 
            headers: { Authorization: `Bearer ${token}` } 
          });
          setDocuments(res.data);
        } catch (err) {
          console.error(err);
        }
      }
    };
    fetchDocuments();
  }, []);

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col items-center">
      <div className="container mx-auto p-4 flex flex-col lg:flex-row gap-6 max-w-7xl">
        
        {/* Sidebar */}
        <div className="lg:w-1/3 flex flex-col gap-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
            <h2 className="text-xl font-bold text-gray-800 mb-4">Upload Target Document</h2>
            <Upload onUpload={() => window.location.reload()} />
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex-1">
            <h2 className="text-xl font-bold text-gray-800 mb-4">Your Documents</h2>
            {documents.length === 0 ? (
              <p className="text-sm text-gray-500 italic">No documents uploaded yet.</p>
            ) : (
              <div className="flex flex-col gap-3 max-h-96 overflow-y-auto pr-2">
                {documents.map(doc => (
                  <div 
                    key={doc._id} 
                    className={`p-3 rounded-lg cursor-pointer transition-all duration-200 border ${selectedDoc?._id === doc._id ? 'bg-indigo-50 border-indigo-300 text-indigo-700' : 'bg-gray-50 border-gray-200 text-gray-700 hover:bg-gray-100 hover:border-gray-300'}`}
                    onClick={() => setSelectedDoc(doc)}
                  >
                    <div className="font-medium truncate" title={doc.filename}>{doc.filename}</div>
                    <div className="text-xs text-gray-400 mt-1">Click to analyze</div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        {/* Main Content Area */}
        <div className="lg:w-2/3 flex flex-col gap-6 w-full">
          {selectedDoc ? (
            <>
              <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                <h2 className="text-2xl font-bold text-gray-800 mb-1 border-b pb-4">{selectedDoc.filename}</h2>
                <div className="mt-4 flex flex-col gap-6">
                  {/* Tools go here seamlessly */}
                  <Summary docId={selectedDoc._id} />
                  <Quiz docId={selectedDoc._id} />
                  <Chat docId={selectedDoc._id} />
                </div>
              </div>
            </>
          ) : (
            <div className="bg-white p-12 rounded-xl shadow-sm border border-gray-100 flex flex-col items-center justify-center h-full text-center min-h-[400px]">
              <div className="w-16 h-16 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mb-4">
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
              </div>
              <h3 className="text-lg font-semibold text-gray-800 mb-2">No Document Selected</h3>
              <p className="text-gray-500 max-w-sm">Select a document from the sidebar to view its summary, generate an interactive quiz, or chat directly with the context of the file.</p>
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

export default Dashboard;
